+        self.config.min_difficulty = orig_min;
+        self.config.max_difficulty = orig_max;
+
+        puzzles
+    }
+}
+
+/// Constraint type enumeration
+#[derive(Clone, Debug)]
+enum ConstraintType {
+    Year,
+    Month,
+    DayOfMonth,
+    DayOfWeek,
+    DayRange,
